					loopSessionID,
					time.Time{}, // lastActivityAt: caller lacks liveness snapshot; treat as stale → always count
				); skip {
					applyExecutionRoutingIntentReport(&exclusionReport, routingIntent, "", "")
					return exclusionReport, nil
				}

